  celula[1].presL = pmed;
  celula[0].pres = pmed;
  celula[0].presini = pmed;
  celula[1].presLini = pmed;
  celula[0].presauxL = pmed;
  tmed = celula[0].calor.Textern1;
  celula[0].tempL = tmed;
  celula[0].temp = tmed;
  celula[0].tempini = tmed;
  celula[1].tempL = tmed;
  double rho0;
  if (0 <= arq.celdescargaP) rho0 = celula[0].fluicol.MasEspFlu(pmed, tmed);
  else rho0 = celula[0].flui.MasEspGas(pmed, tmed);
  double rho1;
  rho1=celula[0].fluicol.MasEspFlu(pmed,tmed);

  celula[0].FW = 0;
  celula[0].FWini = 0;
  celula[0].arranjo = 0;
  celula[0].QLL = 0;
  celula[1].QLL = celula[0].QLL;
  celula[0].QL = 0;
  celula[0].QG = 0;
  celula[0].rpL = rho1;
  celula[0].rpC = rho1;
  celula[1].rpL = celula[0].rpC;
  celula[0].rcL = rho1;
  celula[0].rcC = rho1;
  celula[1].rcL = celula[0].rcC;

  celula[0].MC = 0.;
  celula[0].ML = 0.;
