    double dx1 = 0.5 * celula[i].dx;
    pmed -= rho0 * 9.81 * dx0 * sinl(celula[i - 1].duto.teta) / 98066.52;
    tmed = celula[i].calor.Textern1;
    double taux = (dx0 * celula[i - 1].temp + dx1 * tmed) / (dx0 + dx1);
    celula[i].presaux = pmed;
