  	  double hidroM=-0.5*rhoM*celulaG[posicM2].dx0*sinl(celulaG[posicM2].duto.teta)/98066.52;
  	  double hidroJ=0.5*rhoJ*celulaG[posicM2+1].dx0*sinl(celulaG[posicM2+1].duto.teta)/98066.52;
