				double rccin = celula[i+1].rcCi;//celula[i+1].fluicol.MasEspFlu(celula[i+1].presaux,  0.5*(celula[i].temp+celula[i+1].temp));
				double rholcin = (1. - betmed) * rpcin + betmed * rccin;
