				cinetico = rholcin*(1-alf)*areaaux*(0.5*(ulmed*ulmed-ulmedini*ulmedini))/celula[i].dt+
						rhogcin*alf*areaaux*(0.5*(ugmed*ugmed-ugmedini*ugmedini))/celula[i].dt+
						((celula[i+1].MC-celula[i+1].Mliqini)*ugmed*(ugmed-ugmed0)/dxCin+
						  celula[i+1].Mliqini*ulmed*(ulmed-ulmed0)/dxCin);

