    //if (celula[ind].QG*0.99+celula[ind].QL*0.01 < 0.)
      betI = celula[ind].betPigE;        //duvidabeta
    double betneg;
    if (ind > 0) {
      betneg = betaE;

    } else
      betneg = celula[ind].bet;

    double pmed;
    double pmed0=0.;

    pmed = presE;
    if (ind > 0)
      pmed0 = presE;
    if (ind == ncel)
      pmed = celula[ind].pres;
    else
      pmed0 = presE;
    double tmed = tempE;

    double tmed0;
    tmed0 = tmed;

    double correcHor=1.;
    if(fabsl(celula[ind].duto.teta)<1e-10){
    	if(celula[ind].acsr.tipo!=5 || celula[ind].acsr.chk.AreaGarg>1e-10){
    		if(celula[ind].angEsq<0 && celula[ind].angDir<0)correcHor=-1.;
    		else if(celula[ind].angEsq>0 && celula[ind].angDir>0)correcHor=1.;
    	}
    	else{
    		if(celula[ind].angDir<0)correcHor=-1.;
    		else if(celula[ind].angDir>0)correcHor=1.;
    	}
    }

    double rlm;
