        double bo0 = flue.BOFunc(celula[i - 1].pres, celula[i - 1].temp);
        double ba0 = flue.BAFunc(celula[i - 1].pres, celula[i - 1].temp);
        fwe = flue.BSW*ba0 / (bo0 + ba0*flue.BSW - flue.BSW * bo0);

