      //if ((celula[i-1].MC-celula[i - 1].Mliqini)*0.99+0.01*celula[i - 1].Mliqini < 0) betL = celula[i - 1].betPigE;//duvidabeta

      double rhol = (1 - betI) * rl + betI * celula[i].fluicol.MasEspFlu(celula[i].presaux, tmed);
