 void SProd::atenuaDtMax(){

	   dtCFL.push_back(dtauxCFL);
	   dtSim.push_back(dtauxFinal);
	   dtCFLTotal += dtauxCFL;
	   dtSimTotal += dtauxFinal;
	   kontarestriDt++;
	   if (kSP > 10) {
	 	  dtCFLTotal -= dtCFL.front();
	 	  dtCFL.erase(dtCFL.begin());
	 	  dtSimTotal -= dtSim.front();
	 	  dtSim.erase(dtSim.begin());
	 	  if(kontarestriDt>10 && restriDt==1){
	 		 restriDt=0;
	 		 kontarestriDt=0;
	 		 //modeloCompleto=1;
	 	  }
	   }
	   dtCFLMed=dtCFLTotal/10;
	   dtSimMed=dtSimTotal/10.;
	   if((dtSimMed<dtCFLMed/2 && kontarestriDt>10)){
		   restriDt=1;
		   kontarestriDt=0;
		   //modeloCompleto=0;
	   }
 }

void SProd::avaliaVariaDpDt(double razMast, double razMast0,int vexpli){
	   double dpdtRef=2*arq.taxaDespre;
	   //modeloCompleto=0;
	   //atenuaSegrega();
	   double modDpDt=0.;
	   double modDTDt=0.;
	   double dpdtMax=0.;
	   double dTdtMax=0.;
	   if(modeloCompleto==1){
		   modeloCompleto=0;
		   int i=0;
	   	   while( i<ncel){
		   int nBloco=10;
	  	  	  if(ncel-i<nBloco)nBloco=ncel-i;
	  	  	  for(int j=0; j<nBloco;j++){
	  	  		  modDpDt+=fabsl(celula[i+j].pres-celula[i+j].presini)/(dt);
	  	  		  modDTDt+=fabsl(celula[i+j].temp-celula[i+j].tempini)/(dt);
	  	  	  }
	  	  	  i+=nBloco;
	  	  	  modDpDt/=nBloco;
	  	  	  modDTDt/=nBloco;
	  	  	  if(modDpDt>dpdtMax)dpdtMax=modDpDt;
	  	  	  if(modDTDt>dTdtMax)dTdtMax=modDTDt;
	  	  	  if(modDpDt>dpdtRef)modeloCompleto=1;
	  	  	  modDpDt=0.;
	  	  	  modDTDt=0.;
	   	   }
	   	   taxaDpMax.push_back(dpdtMax);
	   	   taxaDTMax.push_back(dTdtMax);
	   	   if(taxaDpMax.size()>10)taxaDpMax.erase(taxaDpMax.begin());
	   	   if(taxaDTMax.size()>10)taxaDTMax.erase(taxaDTMax.begin());
	   	   int nvec=taxaDpMax.size();
	   	   int nvecT=taxaDTMax.size();
	   	   DpMaxMed=0.;
	   	   DTMaxMed=0.;
	   	   for(int i=0;i<nvec;i++)DpMaxMed+=taxaDpMax[i];
	   	   for(int i=0;i<nvecT;i++)DTMaxMed+=taxaDTMax[i];
	   	   DpMaxMed/=nvec;
	   	   DTMaxMed/=nvecT;
	   	   if(DpMaxMed>dpdtRef)modeloCompleto=1;
	   	   //if(celula[ncel-1].pres<20)modeloCompleto=0;
	   	   if( /*razMast<1e-3 &&*/ chokeSup.AreaGarg/celula[ncel - 1].duto.area<1e-3 &&
	   			(DpMaxMed>arq.taxaDespre/10. || DTMaxMed>0.001)   )modeloCompleto=1;
	   	   int linAberta=1;//caso varias valvulas
	   	   for(int i=0;i<=arq.nvalv; i++)if(vRazMast1[i]<=1e-3)linAberta=0;//caso varias valvulas
	   	   if((linAberta==1 && chokeSup.AreaGarg/celula[ncel - 1].duto.area>1e-3))modeloCompleto=1;//caso varias valvulas
	   	   //if((razMast>1e-3 && chokeSup.AreaGarg/celula[ncel - 1].duto.area>1e-3))modeloCompleto=1;//caso so Master
	   	  // if(razMast<1e-3 && masChkSup ==0 && (fabsl(pGSup-pGSupIni)/dt)<dpdtRef)modeloCompleto=0;
	   }
	   //if(razMast!=razMast0 /*|| restriDt==1*/)modeloCompleto=0;//caso so Master
	   for(int i=0;i<=arq.nvalv; i++)if(vRazMast1[i]!=vRazMast0[i] )modeloCompleto=0;//caso varias valvulas
	   if((DpMaxMed>10 || DTMaxMed>1) && modeloCompleto==1 && vexpli==0  ){
		   modeloCompleto=0;
	   }
	   //modeloCompleto=0;
}

void SProd::aberturaVal0(){
	   int celpos = arq.master1.posic;
	   vRazMast0[0]=celula[celpos].acsr.chk.AreaGarg/celula[celpos].duto.area;
	   for(int i=1;i<=arq.nvalv;i++){
		   celpos=arq.valv[i-1].posicP;
		   vRazMast0[i]=celula[celpos].acsr.chk.AreaGarg/celula[celpos].duto.area;
	   }
}
void SProd::aberturaVal1(){
	   int celpos = arq.master1.posic;
	   vRazMast1[0]=celula[celpos].acsr.chk.AreaGarg/celula[celpos].duto.area;
	   for(int i=1;i<=arq.nvalv;i++){
		   celpos=arq.valv[i-1].posicP;
		   vRazMast1[i]=celula[celpos].acsr.chk.AreaGarg/celula[celpos].duto.area;
	   }
}
void SProd::restringeDTporValv(){

	if(arq.ConContEntrada==0 && (*vg1dSP).chaveRedeParalela==0){
		int celpos;
		double dtaux=celula[0].dt;
		if(reinicia==-1){
			for(int i=1;i<=ncel;i++) if(dtaux>celula[i].dt) dtaux=celula[i].dt;
		}
		double dtvec[arq.nvalv+1];
		for(int i=0; i<=arq.nvalv;i++)dtvec[i]=celula[0].dt;
		for(int i=0; i<=arq.nvalv;i++){
			if(i==0)celpos = arq.master1.posic;
			else celpos=arq.valv[i-1].posicP;
			if(vRazMast1[i]<vRazMast0[i] && (vRazMast1[i]<=1.1*arq.master1.razareaativ && vRazMast1[i]>=1e-3*arq.master1.razareaativ)){
				if(celula[celpos].alf<0.05){
					if(celula[celpos].alf<0.01)momentoDesesp+=1.5;
					else momentoDesesp=1;
					if(momentoDesesp<1.)momentoDesesp=1.;
					celula[celpos].fontemassGL+=momentoDesesp*10000*celula[celpos].flui.Deng*1.225/86400;
					celula[celpos-1].fontemassGR=celula[celpos].fontemassGL;
				}
				if(celula[celpos].alf<0.5)vRazMastCrit[i]=0.01;
			}
			else momentoDesesp=0.;
			if(vRazMast1[i]<vRazMast0[i] && (vRazMast1[i]<=1.1*arq.master1.razareaativ && vRazMast1[i]>=vRazMastCrit[i]*arq.master1.razareaativ)){
				//if(i==0)celpos = arq.master1.posic;
				//else celpos=arq.valv[i-1].posicP;
				double raz=20.;
				if(celula[celpos].alf<0.5)raz=40.;
				dtvec[i]=dtaux;
				if(dtvec[i]>1)dtvec[i]=1.;
				if(celula[celpos].alf<0.5)dtvec[i]=0.1+0.9*(celula[celpos].alf)/0.5;
				//celula[0].dt=dt/raz;
				dtvec[i]/=raz;
				reinicia=-1;
			}
		}
		dtaux=dtvec[0];
		for(int i=1; i<=arq.nvalv;i++)
			if(dtvec[i]<dtaux)dtaux=dtvec[i];
		celula[0].dt=dtaux;
	}
}

void SProd::solveLinGas() {
  if (arq.lingas > 0) {
    double tg;
    //subtempoGas(celulaG,chokeVGL,matglobG,termolivreG,
    //dt,celula,ColunaAnulaIni,ColunaAnulaFim,
    //AnulaColunaIni,AnulaColunaFim,posicVGLP,posicVGLG, arq.nvalvgas);
    ValvGasTrans();
    for (int i = 0; i < arq.nvalvgas; i++) {
      int posGLP = posicVGLP[i];
      int posGLG = posicVGLG[i];
      if (posGLG < celInter || (posGLG == celInter && celulaG[posGLG].razInter > 0.5)) {
        celula[posGLP].acsr.injg.QGas = celulaG[posGLG].massfonteCH * 86400. / celulaG[posGLG].flui.MasEspGas(1., 15.);
        celula[posGLP].acsr.injg.tipoflu = 0;
      } else {
        celula[posGLP].acsr.injg.QGas = celulaG[posGLG].massfonteCH;
        celula[posGLP].acsr.injg.tipoflu = 1;
      }
      //double tg;
      if (posGLG < celInter || (posGLG == celInter && celulaG[posGLG].razInter > 0.5)) {
        if (chokeVGL[i].presEstag > chokeVGL[i].presGarg) {
          tg = TempDescGL(i);	        		//alteracao2
        } else tg = celula[posGLP].temp;
        celula[posGLP].acsr.injg.temp = tg;
        if (celula[posGLP].acsr.injg.temp < -50) celula[posGLP].acsr.injg.temp = -50;
      } else celula[posGLP].acsr.injg.temp = chokeVGL[i].tempEstag;
      celulaG[posGLG].pEstag=chokeVGL[i].presEstag;
      celulaG[posGLG].tEstag=chokeVGL[i].tempEstag;
      celulaG[posGLG].pGarg=chokeVGL[i].presGarg;
      celulaG[posGLG].tGarg=chokeVGL[i].tempGarg;
      celulaG[posGLG].qGarg=chokeVGL[i].qGarg;
      celulaG[posGLG].areaGarg=chokeVGL[i].areagarg;
    }
    subtempoGas();
  }
}

