///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////
double SProd::marchaProdPresPres3(double mchute) {

  int corrigechute = 1;
  double alfini=0.;
  double betini=0.;

  if (celula[0].acsr.tipo == 1) {
    celula[0].temp = celula[0].acsr.injg.temp;
	if(arq.flashCompleto==2){
		if(arq.tabelaDinamica==0)celula[0].flui.atualizaPropComp(celula[0].pres, celula[0].temp);
	    celula[0].acsr.injg.FluidoPro.atualizaPropComp(celula[0].pres, celula[0].temp,-1,NULL,NULL,celula[0].acsr.injg.seco);
	}
    celula[0].acsr.injg.QGas = mchute;
  } else if (celula[0].acsr.tipo == 2) {
    celula[0].temp = celula[0].acsr.injl.temp;
	if(arq.flashCompleto==2){
		if(arq.tabelaDinamica==0)celula[0].flui.atualizaPropComp(celula[0].pres, celula[0].temp);
	    celula[0].acsr.injl.FluidoPro.atualizaPropComp(celula[0].pres, celula[0].temp);
	}
    celula[0].acsr.injl.QLiq = mchute;
  }

  if (celula[0].acsr.tipo == 1){
	  if(celula[0].acsr.injg.seco==1){
		  alfini=1.;
		  betini=0.;
	  }
	  else{
		  double masgas = celula[0].acsr.injg.VMas(celula[0].pres, celula[0].temp);
		  //double tit=celula[0].acsr.injg.FluidoPro.FracMassHidra(1., 20.);
		  double tit;
		  if(arq.flashCompleto!=2)tit=celula[0].acsr.injg.FluidoPro.FracMassHidra(1., 20.);
		  else tit=celula[0].acsr.injg.FluidoPro.dStockTankVaporMassFraction;
		  double masT=masgas/tit;
		  tit=celula[0].acsr.injg.FluidoPro.FracMassHidra(celula[0].pres, celula[0].temp);
		  double qgas=masT*tit/
				           celula[0].acsr.injg.FluidoPro.MasEspGas(celula[0].pres,celula[0].temp);
		  double qliq=masT*(1.-tit)/
				           celula[0].acsr.injg.FluidoPro.MasEspLiq(celula[0].pres,celula[0].temp);
		  double qcomp=celula[0].acsr.injg.razCompGas*
				            celula[0].acsr.injg.QGas*celula[0].acsr.injg.fluidocol.MasEspFlu(1.,20.)/
				            celula[0].acsr.injg.fluidocol.MasEspFlu(celula[0].pres,celula[0].temp);
		  qcomp/=86400.;
		  alfini=qgas/(qliq+qcomp+qgas);
		  //betini=0.;
		  if((fabsl(qcomp)+fabsl(qliq))>1e-15)betini=fabsl(qcomp)/(fabsl(qcomp)+fabsl(qliq));
		  else betini=0.;
	  }
  }
  else if (celula[0].acsr.tipo == 2){
	  double qgas=celula[0].acsr.injl.QLiq*(1-celula[0].acsr.injl.bet)*
			  (1.-celula[0].acsr.injl.FluidoPro.BSW)*
			  (celula[0].acsr.injl.FluidoPro.RGO-
			   celula[0].acsr.injl.FluidoPro.rDgD*celula[0].acsr.injl.FluidoPro.RS(celula[0].pres,celula[0].temp)*6.29/35.31467)*
			  celula[0].acsr.injl.FluidoPro.Deng * 1.225/celula[0].acsr.injl.FluidoPro.MasEspGas(celula[0].pres,celula[0].temp);
	  double qliq=celula[0].acsr.injl.QLiq*(1-celula[0].acsr.injl.bet)*
			  (1.-celula[0].acsr.injl.FluidoPro.BSW)*celula[0].acsr.injl.FluidoPro.BOFunc(celula[0].pres,celula[0].temp)+
			  celula[0].acsr.injl.QLiq*(1-celula[0].acsr.injl.bet)*
			  celula[0].acsr.injl.FluidoPro.BSW*celula[0].acsr.injl.FluidoPro.BAFunc(celula[0].pres,celula[0].temp)+
			  celula[0].acsr.injl.QLiq*celula[0].acsr.injl.bet;
	  alfini=qgas/(qliq+qgas);
	  betini=celula[0].acsr.injl.bet;
  }

  celula[0].tempL = celula[0].temp;
  celula[1].tempL = celula[0].temp;
  celula[0].tempini = celula[0].temp;

  celula[0].ML = 0.;
  celula[0].MC = 0.;
  celula[1].ML = 0.;
  celula[0].MliqiniL = 0.;
  celula[0].Mliqini = 0.;
  celula[1].MliqiniL = 0.;
  celula[0].MComp = 0.;
  celula[0].QLL = 0.;
  celula[0].QL = 0;
  celula[1].QLL = 0.;
  celula[0].QG = 0.;

  int i;

  celula[0].presauxL = celula[0].pres;
  celula[0].presLini = celula[0].pres;
  celula[0].presL = celula[0].pres;
  //celula[0].pres=pchute;
  celula[1].presL = celula[0].pres;
  celula[0].presini = celula[0].pres;
  celula[1].presLini = celula[0].pres;
  celula[0].presaux = celula[0].pres;
  celula[1].presauxL = celula[0].pres;

  celula[0].alf = alfini;
  celula[0].alfini = alfini;
  celula[0].bet = betini;
  celula[0].betini = betini;
  celula[1].alfL = celula[0].alf;
  celula[1].alfLini = celula[0].alf;
  celula[0].alfPigD = celula[0].alf;
  celula[0].alfPigDini = celula[0].alf;
  celula[0].alfPigE = celula[0].alf;
  celula[0].alfPigEini = celula[0].alf;
  celula[1].betL = celula[0].bet;
  celula[1].betLini = celula[0].bet;
  celula[0].betPigD = celula[0].bet;
  celula[0].betPigDini = celula[0].bet;
  celula[0].betPigE = celula[0].bet;
  celula[0].betPigEini = celula[0].bet;
  celula[0].betI = celula[0].bet;
  celula[1].betLI = celula[0].bet;

  /*if (iterperm == 0) {
    celula[0].alf = 0.;
    celula[0].alfini = 0.;
    celula[0].bet = 0.;
    celula[0].betini = 0.;
    celula[1].alfL = celula[0].alf;
    celula[1].alfLini = celula[0].alf;
    celula[0].alfPigD = celula[0].alf;
    celula[0].alfPigDini = celula[0].alf;
    celula[0].alfPigE = celula[0].alf;
    celula[0].alfPigEini = celula[0].alf;
    celula[1].betL = celula[0].bet;
    celula[1].betLini = celula[0].bet;
    celula[0].betPigD = celula[0].bet;
    celula[0].betPigDini = celula[0].bet;
    celula[0].betPigE = celula[0].bet;
    celula[0].betPigEini = celula[0].bet;
    celula[0].betI = celula[0].bet;
    celula[1].betLI = celula[0].bet;
  } else {
    celula[0].alf = celula[1].alf;
    celula[0].alfini = celula[1].alf;
    celula[0].bet = celula[1].bet;
    celula[0].betini = celula[1].bet;
    celula[1].alfL = celula[0].alf;
    celula[1].alfLini = celula[0].alf;
    celula[0].alfPigD = celula[0].alf;
    celula[0].alfPigDini = celula[0].alf;
    celula[0].alfPigE = celula[0].alf;
    celula[0].alfPigEini = celula[0].alf;
    celula[1].betL = celula[0].bet;
    celula[1].betLini = celula[0].bet;
    celula[0].betPigD = celula[0].bet;
    celula[0].betPigDini = celula[0].bet;
    celula[0].betPigE = celula[0].bet;
    celula[0].betPigEini = celula[0].bet;
    celula[0].betI = celula[0].bet;
    celula[1].betLI = celula[0].bet;
  }*/
  iterperm=0;
  while(iterperm<3){
  i = 1;
  while (i <= ncel && celula[i - 1].pres >= 1.) {

    RenovaPresPermMon(i, 0);
    atualizaPeriPmonProd(i);
    if(arq.flashCompleto!=2)RenovaMassPerm(i);
    else RenovaMassPermComp(i);
    RenovaTempPerm(i, 0);
    if(isnan(celula[i].temp))NumError("Temperatrura na linha de producao com valor NaN");
    /*if(arq.flashCompleto==2){
    	if(i>0)
    	celula[i].flui.atualizaPropComp(celula[i].pres, celula[i].temp,celula[i-1].flui.dCalculatedBeta,
 			   celula[i-1].flui.oCalculatedLiqComposition,celula[i-1].flui.oCalculatedVapComposition);
    	else celula[i].flui.atualizaPropComp(celula[i].pres, celula[i].temp);
    }*/
    if(arq.usaTabela==1 && (celula[i].temp-arq.tabent.tmin) < (*vg1dSP).localtiny)celula[i].temp=arq.tabent.tmin;
    atualizaPeriTempProd(i);
    RenovaPresPermJus(i, 0);
    atualizaPeriPjusProd(i);
    if(arq.tipoFluido==0)RenovaTransMassPerm(i - 1);
    else RenovaTransMassPermGas(i - 1);
    if (arq.ordperm > 1) {
      double D0presaux = celula[i].presaux - celula[i - 1].pres;
      double D0pres = celula[i].pres - celula[i].presaux;
      double D0temp = celula[i].temp - celula[i - 1].temp;
      RenovaPresPermMon(i, 1);
      atualizaPeriPmonProd(i);
      RenovaMassPerm(i);
      RenovaTempPerm(i, 1);
      RenovaPresPermJus(i, 1);
      celula[i].pres = 0.5 * (celula[i].presaux + D0pres + celula[i].pres);
      celula[i].presaux = 0.5 * (celula[i - 1].pres + D0presaux + celula[i].presaux);
      celula[i].temp = 0.5 * (celula[i - 1].temp + D0temp + celula[i].temp);
      atualizaPeriPjusProd(i);
      atualizaPeriPmonProd(i);
      atualizaPeriTempProd(i);
      RenovaMassPerm(i);
      if(arq.tipoFluido==0)RenovaTransMassPerm(i - 1);
      else RenovaTransMassPermGas(i - 1);

    }
    /*celula[i].rpC = celula[i].rpCi = celula[i].flui.MasEspLiq(celula[i].pres, celula[i].temp);
    celula[i].rcC = celula[i].rcCi = celula[i].fluicol.MasEspFlu(celula[i].pres, celula[i].temp);
    celula[i].rpL = celula[i].rpLi = celula[i].flui.MasEspLiq(celula[i].presL, celula[i].tempL);
    celula[i].rcL = celula[i].rcLi = celula[i].fluicol.MasEspFlu(celula[i].presL, celula[i].tempL);
    celula[i - 1].rpR = celula[i - 1].rpRi = celula[i].rpC;
    celula[i - 1].rcR = celula[i - 1].rcRi = celula[i].rcC;*/

    //RenovaMassPerm(i);
    //RenovaTempPerm(i);
    //RenovaTransMassPerm(i-1);
    i++;
    if (celula[i - 1].pres <= pGSup) return -1e10;
  }
  iterperm++;
  }

  //if(fabsl(celula[ncel - 1].MR)>1e-15)monitConvPermBase=fabsl(celula[ncel - 1].MR);
  //else
	  monitConvPermBase=1.;
  return 0. - celula[ncel - 1].MR;
}

double SProd::buscaProdPresPresPerm3(double chute, double maxvaz) {

  revPerm=0;
  monitConvPerm=1000.;
  double taux;
  double pchute=arq.CCPres.pres[0];
  double vazTot=0.;
  if(chute<0.){
	  for (int i = 0; i < ncel; i++) {
		  taux = arq.celp[i].textern;
		  double rhol = celula[i].flui.MasEspLiq(pchute, taux);
		  double rhog = celula[i].flui.MasEspGas(pchute, taux);
		  //se o sistema nao for um anel principal de GL
		  //para a estimativa de pressao, se utilizara so a hidrostatica de liquido, o que dara um
		  //chute inicial de pressao muito alta
		  double alfa = 0.1;
		  if((*vg1dSP).chaverede==1 && chuteHol<0.5 && chuteHol>-1e-15)alfa=1.-chuteHol*2.;
		  double rhomix = (1. - alfa) * rhol + alfa * rhog;
		  double dxmed = 0.5 * (celula[i].dx + celula[i + 1].dx);
		  //avanco da pressao por meio da hidrostatica e da perda por friccao estimada
		  pchute -= ((rhomix * 9.81 * sinl(celula[i].duto.teta) * dxmed) / 98066.5);
		  //incremento de pressao devido a algum ganho de pressao constante em alguma celula
		  if (celula[i].acsr.tipo == 7) pchute -= celula[i].acsr.delp;
		  //caso exista alguma IPR no meio do duto, verifica se a pressao estimada esta menor que
		  //a pressao estatica, nao se trabalha com vazoes negativas neste solver
		  //para evitar isto, se corrige a pressao para um valor proximo da
		  //pressao estatica da IPR da celula
		  if (celula[i].acsr.tipo == 3 && ((celula[i].acsr.ipr.Pres - pchute) >  0.0) && i==ncel-1){

			  pchute=-(10/celula[i - 1].acsr.ipr.ip)+celula[i - 1].acsr.ipr.Pres;
			  if(pchute<0.99* celula[i - 1].acsr.ipr.Pres)pchute = 0.99* celula[i - 1].acsr.ipr.Pres;
		  }
		  double adVaz=0.;
		  if (celula[i].acsr.tipo == 3)adVaz=-(celula[i].acsr.ipr.Pres-pchute)*celula[i].acsr.ipr.ip;
		  else if (celula[i].acsr.tipo == 1 && arq.tipoFluido==1)adVaz=-celula[i].acsr.injg.QGas;
		  else if (celula[i].acsr.tipo == 2 && arq.tipoFluido==0)adVaz=-celula[i].acsr.injl.QLiq;
		  else if (celula[i].acsr.tipo == 9 && celula[0].acsr.tipo == 1){
			  //celula[i].acsr.fontechk.VMas();
			  //adVaz=-celula[i].acsr.fontechk.masG*86400./celula[i].acsr.fluido.MasEspGas(1., 20.);
			  adVaz=10000.;
		  }
		  else if (celula[i].acsr.tipo == 9 && celula[0].acsr.tipo == 2){
			  //adVaz=-(celula[i].acsr.fontechk.masP+celula[i].acsr.fontechk.masC)*86400./celula[i].acsr.fluido.MasEspLiq(1., 20.);
			  adVaz=1000.;
		  }

		  vazTot+=adVaz;
		  if(vazTot<0)vazTot-=adVaz;
		  //tambÃ©m se evita um chute com valores maiores que o limite maximo de uma tabela
		  //no caso de se estar usando PVTSim
		  if(arq.usaTabela==1 && (arq.tabent.pmax - pchute) < (*vg1dSP).localtiny)pchute = 0.9*arq.tabent.pmax;
	  }
	  chute=vazTot;
  }
  double mchute = chute;
  double val = marchaProdPresPres2(mchute);
  buscaIni=1;
  int kontaiter=0;
  if (val < -0.9e10) {
    while (val < -0.9e10 && kontaiter<400) {
      //if (celula[0].acsr.tipo == 1) {
        mchute *= (1.-arq.buscaFC);
        val = marchaProdPresPres2(mchute);
        //if (celula[0].acsr.injg.QGas < 1e-3) {
        if (mchute < 1e-5) {
          if ((*vg1dSP).chaverede == 0 && arq.AS==0) NumError(
              "Busca de valores iniciais para calculo de zero de funcao em buscaProdPresPresPerm atingiu maximo de iteracoes");
          else {
            if ((*vg1dSP).iterRede > 0) return -1.1e10;
            else return 1.1e10;
          }
        }
      //}
      /*else if (celula[0].acsr.tipo == 2) {
        mchute *= 0.9;
        if (celula[0].acsr.injl.QLiq < 1e-3) {
          if ((*vg1dSP).chaverede == 0) NumError(
              "Busca de valores iniciais para calculo de zero de funcao em buscaProdPresPresPerm atingiu maximo de iteracoes");
          else {
            if ((*vg1dSP).iterRede > 0) return -1.1e6;
            else return 1.e6;
          }
        }
      }*/
      val = marchaProdPresPres2(mchute);
      kontaiter++;
    }
  }
  double mchuteAux;
  double mchute2 = mchute;
  double chutelim = 0.;
  kontaiter = 0;

  double chuteNeg=0.;
  double chutePos=0.;

  int testaEscoa=1;
  if(fabsl(val)<1e-3)return mchute;
  else {
	  if (val < 0.) {
		  chuteNeg=mchute;
		  while (val < 0) {
			  mchuteAux = mchute2;
			  mchute2 *= (1.-arq.buscaFC);
      //if (mchute2 <= chutelim) mchute2 = 0.5 * (mchuteAux + chutelim);
			  val = marchaProdPresPres2(mchute2);
			  if(val<0 && val>-0.9e10)chuteNeg=mchute2;
			  kontaiter++;
			  double vel=mchute2;
			  double bet = celula[1].bet;
			  double alf = celula[1].alf;
			  double p1=celula[0].pres;
			  double t1=celula[0].temp;
			  double rC = celula[0].fluicol.MasEspFlu(p1, t1);
			  double rP = celula[0].flui.MasEspLiq(p1, t1);
			  double rG = celula[0].flui.MasEspGas(p1, t1);
			  double rmisL = (1 - bet) * rP + bet * rC;
			  double rmis=(1-alf)*rmisL+alf*rG;
			  double rCst=  celula[0].fluicol.MasEspFlu(1., 20.);
			  double rPst = celula[0].flui.MasEspLiq(1., 20.);
			  double rGst = celula[0].flui.MasEspGas(1., 20.);
			  double rmisLst=(1 - bet) * rPst + bet * rCst;
			  double multiplica;
			  if(celula[0].acsr.tipo==2)multiplica=rmisLst;
			  else multiplica=rGst;
			  vel=mchute2*multiplica/(rmis*celula[0].duto.area*86400);
			  if (kontaiter > 200 && vel>0.01) {
				  if ((*vg1dSP).chaverede == 0 && arq.AS==0) NumError(
						  "Busca de valores iniciais para calculo de zero de funcao em buscaProdPresPresPerm atingiu maximo de iteracoes");
				  else {
					  if ((*vg1dSP).iterRede > 0) return -1.1e10;
					  else return 1.1e10;
				  }
			  }
			  if(vel<=0.01){
				  testaEscoa=0;
				  val=1.;
			  }
			  while (val < -0.9e10) {
				  chutelim = mchute2;
				  mchute2 = 0.5 * (mchute2 + mchuteAux);
				  val = marchaProdPresPres2(mchute2);
				  if(val<0 && val>-0.9e10)chuteNeg=mchute2;
				  kontaiter++;
				  if (kontaiter > 200) {
					  if ((*vg1dSP).chaverede == 0 && arq.AS==0) NumError(
							  "Busca de valores iniciais para calculo de zero de funcao em buscaProdPresPresPerm atingiu maximo de iteracoes");
					  else {
						  if ((*vg1dSP).iterRede > 0) return -1.1e10;
						  else return 1.1e10;
					  }
				  }
			  }
		  }
		  chutePos=mchute2;
	  } else if (val > 0.) {
		  chutePos=mchute;
		  while (val > 0) {
			  mchuteAux = mchute2;
			  mchute2 *= (1.+arq.buscaFC);
      //if (mchute2 >= chutelim) mchute2 = 0.5 * (mchuteAux + chutelim);
			  val = marchaProdPresPres2(mchute2);
			  if((*vg1dSP).chaverede!=0 && mchute2>maxvaz && maxvaz>0){
				  testaEscoa=0;
				  val=-1.;
			  }
			  if(val>0 && val<0.9e10)chutePos=mchute2;
			  kontaiter++;
			  if (kontaiter > 200) {
				  if ((*vg1dSP).chaverede == 0 && arq.AS==0) NumError(
						  "Busca de valores iniciais para calculo de zero de funcao em buscaProdPresPresPerm  atingiu maximo de iteracoes");
				  else {
					  if ((*vg1dSP).iterRede > 0) return -1.1e10;
					  else return 1.1e10;
				  }
			  }
			  while (val >0.9e10) {
				  chutelim = mchute2;
				  mchute2 = 0.5 * (mchute2 + mchuteAux);
        //if(fabsl(pchute2-pchuteAux)<localtiny)pchute2=1.1*pchuteAux;
				  val = marchaProdPresPres2(mchute2);
				  if(val>0 && val<0.9e10)chutePos=mchute2;
				  kontaiter++;

        if (kontaiter > 200) {
        	if ((*vg1dSP).chaverede == 0 && arq.AS==0) NumError(
        			"Busca de valores iniciais para calculo de zero de funcao em buscaProdPresPresPerm atingiu maximo de iteracoes");
        	else {
        		if ((*vg1dSP).iterRede > 0) return -1.1e10;
        		else return 1.1e10;
        	}
        }

			  }
		  }
		  chuteNeg=mchute2;
	  }
  //return falsacorda(mchute, mchute2,2,1);
	  if(testaEscoa==1)return zriddr(chuteNeg, chutePos, 2, 1);
	  else{
		  if (celula[0].acsr.tipo == 1) {
			  celula[0].acsr.injg.QGas = 0.;
		  } else if (celula[0].acsr.tipo == 2) {
			  celula[0].acsr.injl.QLiq = 0.;
		  }
		  return 0.;
	  }
  //return zbrent(mchute, mchute2,2,1); //no caso mono deu problema com este solver, funcionou melhor com a falsa corda
  }
}

