double  SProd::zriddr(double x1,double x2,int prod, int tipoCC){
	double xacc=1e-5;
	int maxit=100;
	double fmin;
	double xmin;
	double fl;
	double fh;
	if(revPerm==0){
		fl=multMarcha(x1, prod, tipoCC);
		fh=multMarcha(x2, prod, tipoCC);
	}
	else{
		//double xTemp=x1;
		//x1=x2;
		//x2=xTemp;
		fl=multMarcha(x1, prod, tipoCC);
		fh=multMarcha(x2, prod, tipoCC);
	}
	if(fabsl(fl)>1e9 || fabsl(fh)>1e9) return 1e10;
	if(fl>=0.){
		if(fl>0.9e10){
			x1*=0.9999;
			fl=multMarcha(x1, prod, tipoCC);
		}
		else{
		   //x1=x1-1*(x2-x1);
			int konta=0;
			while(konta<100 && fl>0.){
				if(revPerm==0){
					if(x2<x1) x1*=1.0001;
					else x1*=0.999;
				}
				else{
					//x1*=1.0001;
					if(x2<x1) x1*=1.0001;
					else x1*=0.999;
				}
				fl=multMarcha(x1, prod, tipoCC);
				konta++;
			}
		}
	}
	else if(fh<=0.){
		if(fh<-0.9e10){
			x2*=1.00001;
			fh=multMarcha(x2, prod, tipoCC);
		}
		else{
		  //x2=x2-1*(x1-x2);
			int konta=0;
			while(konta<100 && fh<0.){
				if(revPerm==0){
					if(x1<x2) x2*=1.0001;
					else x2*=0.999;
				}
				else{
					//x2*=0.999;
					if(x1<x2) x2*=1.0001;
					else x2*=0.999;
				}
				fh=multMarcha(x2, prod, tipoCC);
				konta++;
			}
		}
	}
	if(fabsl(fh)<fabsl(fl)){
		fmin=fh;
		xmin=x2;
	}
	else{
		fmin=fl;
		xmin=x1;
	}
	if((fl>0.0 && fh<0.0) || (fl<0.0 && fh>0.0)){
		double xl=x1;
		double xh=x2;
		double ans=-1.e20;
		for(int j=0;j<maxit;j++){
			double xm=0.5*(xl+xh);
			double fm=multMarcha(xm, prod, tipoCC)/monitConvPermBase;
			if(prod!=0){
				monitConvPerm=fabsl(fm);//monitConvPermBase;
			}
			if(fabsl(fm)<fabsl(fmin)){
				fmin=fm;
				xmin=xm;
			}
			double s=sqrtl(fm*fm-fl*fh);
			if(s==0.0){
				fmin=multMarcha(xmin, prod, tipoCC);
				return xmin;
			}
			double xnew=xm+(xm-xl)*((fl>=fh ? 1.0 : -1.0)*fm/s);
			if(fabsl(xnew-ans)<=xacc ){
				fmin=multMarcha(xmin, prod, tipoCC);
				return xmin;
			}
			ans=xnew;
			double fnew=multMarcha(ans, prod, tipoCC)/monitConvPermBase;
			if(prod!=0){
				monitConvPerm=fabsl(fnew);//monitConvPermBase;
			}
			if(fabsl(fnew)<fabsl(fmin)){
				fmin=fnew;
				xmin=ans;
			}
			if(fabsl(fnew)<=xacc ){
				fmin=multMarcha(xmin, prod, tipoCC);
				return xmin;
			}
			if(SIGN(fm, fnew)!=fm){
				xl=xm;
				fl=fm;
				xh=ans;
				fh=fnew;
			}
			else if(SIGN(fl,fnew)!=fl){
				xh=ans;
				fh=fnew;
			}
			else if(SIGN(fh,fnew)!=fh){
				xl=ans;
				fl=fnew;
			}
			else return -1.e10;
			if(fabsl(xh-xl)<=xacc ){
				fmin=multMarcha(xmin, prod, tipoCC);
				return xmin;
			}

		}
		 return 1.e10;
	}
	else {
		if(fabsl(fl)<=xacc){
			return x1;
		}
		if(fabsl(fh)<=xacc){
			return x2;
		}
		return -1e10;
	}
}


double SProd::hidroreverso(double hol, double vaz,double vazG) {
  double pchute = pGSup;
  double taux;
  celula[ncel].pres = pchute;
  double j = 0.;
  double rmis = 0.;
  double f1 = 0.;
  for (int i = ncel; i > 0; i--) {
  if (vaz > 0. || vazG>0.) {
    taux = arq.celp[0].textern;
    double bet = 0.;
    double visC = celula[i].fluicol.VisFlu(pchute, taux);
    double visP = celula[i].flui.ViscOleo(pchute, taux);
    double visG = celula[i].flui.ViscGas(pchute, taux);
    double visMis = (1 - bet) * visP + bet * visC;
    double rC = celula[i].fluicol.MasEspFlu(pchute, taux);
    double rP = celula[i].flui.MasEspLiq(pchute, taux);
    double rG = celula[i].flui.MasEspGas(pchute, taux);
    rmis = (1 - bet) * rP + bet * rC;
    double rlpA = celula[i].flui.MasEspLiq(1., 15.);
    double rlcA = celula[i].fluicol.MasEspFlu(1.001, 15.);
    double massicC = rlcA * vaz * bet;
    //////////////////////////////////////////////////////////////////////////////////////////////
    double massic = rlpA * vaz * (1. - bet);
    double Rhogs = celula[i].flui.Deng * 1.225;    //cel[ind].acsr.injl.FluidoPro.MasEspGas(1, 15);
    double Rhols = (1000 * 141.5 / (131.5 + celula[i].flui.API)) * (1 - celula[i].flui.BSW)
        + 1000. * celula[i].flui.Denag * celula[i].flui.BSW;
    double multiplicador = (Rhols + celula[i].flui.RGO * Rhogs * (1 - celula[i].flui.BSW));
    //massic *= multiplicador;//alteracao8
    massic=1*vaz * (1. - bet)*multiplicador;
    double fracmasshidra = celula[i].flui.FracMassHidra(pchute, taux);
    double massicP = (1. - fracmasshidra) * massic;
    double massicG = fracmasshidra * massic+vazG*Rhogs;
    j = (massicP / rP + massicC / rC + massicG / rG) / celula[i].duto.area;
    double alfmis = (massicG / rG) / (massicP / rP + massicC / rC + massicG / rG);
    rmis = (1 - alfmis) * rmis + alfmis * rG;
    visMis = (1 - alfmis) * visMis + alfmis * visG;
    double re;
    if (celula[i].duto.revest == 0) re = celula[0].Rey(celula[i].duto.a, j, rmis, visMis);
    else {
      double dhid = 4 * celula[i].duto.area / celula[0].duto.peri;
      re = celula[i].Rey(dhid, j, rmis, visMis);
    }
    f1 = celula[i].fric(re, celula[0].duto.rug / celula[0].duto.a);
  }
  double perdafric = (f1 * rmis * j * fabsl(j) / 2.) * celula[i].duto.peri / celula[i].duto.area;
  //for (int i = ncel; i > 0; i--) {
    taux = arq.celp[i].textern;
    if(i==500){
    	int para;
    	para=0;
    }
    double rhol = celula[i].flui.MasEspLiq(pchute, taux);
    double rhog = celula[i].flui.MasEspGas(pchute, taux);
    double alfa = 1. - hol;
    double rhomix = (1. - alfa) * rhol + alfa * rhog;
    double dxmed = 0.5 * (celula[i].dx + celula[i - 1].dx);
    pchute += ((rhomix * 9.81 * sinl(celula[i].duto.teta) * dxmed + perdafric * dxmed) / 98066.5);
    if (celula[i - 1].acsr.tipo == 7) pchute -= celula[i - 1].acsr.delp;
    if (celula[i - 1].acsr.tipo == 3 && (celula[i - 1].acsr.ipr.Pres - pchute) < (*vg1dSP).localtiny) pchute = 0.99
        * celula[i - 1].acsr.ipr.Pres;
    if (celula[i - 1].acsr.tipo == 15 && (celula[i - 1].acsr.radialPoro.pRes[0] - pchute) < (*vg1dSP).localtiny) pchute = 0.99
        * celula[i - 1].acsr.radialPoro.pRes[0];
    if (celula[i - 1].acsr.tipo == 16 && (celula[i - 1].acsr.poroso2D.dados.pRes - pchute) < (*vg1dSP).localtiny) pchute = 0.99
        * celula[i - 1].acsr.poroso2D.dados.pRes;

    celula[i - 1].dpB = 0.;    //alteracao 1
    if (celula[i - 1].acsr.tipo == 4 && celula[i - 1].acsr.bcs.freqnova > 1. && vaz >= 0.) {    //alteracao 1
      double vazmix = j * celula[i - 1].dutoL.area;
      double rhomis = celula[i - 1].flui.MasEspLiq(pchute, taux);
      double vismis = celula[i - 1].flui.ViscOleo(pchute, taux);
      vazmix *= (86400 / 0.1589876);
      celula[i - 1].acsr.bcs.NovaVis(vismis, rhomis, vazmix);
      celula[i - 1].dpB = 0.3048 * celula[i - 1].acsr.bcs.Hvis * rhomis * 9.82;
    }    //alteracao 1
    if (celula[i - 1].acsr.tipo == 17 && celula[i - 1].acsr.multibcs.freqnova > 1. && vaz >= 0.) {    //alteracao 1
	    double alf0 = celula[i - 1].alf;
	    double bet0 = celula[i - 1].bet;
	    celula[i - 1].acsr.multibcs.flui=celula[i - 1].flui;
	    celula[i - 1].acsr.multibcs.fluicol=celula[i - 1].fluicol;
	    celula[i - 1].acsr.multibcs.marchaMultiBcs(celula[i - 1].QG, celula[i - 1].QL,
	    		pchute, taux,alf0, bet0);
	    celula[i - 1].dpB = celula[i - 1].acsr.multibcs.dpB*98066.52;
    }
    pchute -= celula[i - 1].dpB / 98066.5;    //alteracao 1
    celula[i - 1].pres = pchute;
  }
  return pchute;
}


double SProd::hidroreversoInj(double hol, double vaz) {
  double pchute=0.;
  if (arq.condpocinj.presfundo > 1e-5) pchute = arq.condpocinj.presfundo;
  else if (celula[ncel].acsr.tipo == 3) pchute = celula[ncel].acsr.ipr.Pres;
  else NumError("Sem pressao no fim do tramo e sem IPR-metodo hidroreversoInj");
  double taux;
  double rmis = 0.;
  double j=0.;
  double f1 = 0.;

  if (vaz > 0.) {
    taux = arq.celp[0].textern;
    celula[ncel].pres = pchute;
    double visC = celula[0].acsr.injl.fluidocol.VisFlu(pchute, taux);
    double visMis = visC;
    double rC = celula[0].acsr.injl.fluidocol.MasEspFlu(pchute, taux);
    rmis = rC;
    double rlcA = celula[0].acsr.injl.fluidocol.MasEspFlu(1.001, 15.);
    double massicC = rlcA * vaz;
    //////////////////////////////////////////////////////////////////////////////////////////////
    j = (massicC / rC) / celula[0].duto.area;
    double re;
    if (celula[0].duto.revest == 0) re = celula[0].Rey(celula[0].duto.a, j, rmis, visMis);
    else {
      double dhid = 4 * celula[0].duto.area / celula[0].duto.peri;
      re = celula[0].Rey(dhid, j, rmis, visMis);
    }
    f1 = celula[0].fric(re, celula[0].duto.rug / celula[0].duto.a);
  }
  double perdafric = (f1 * rmis * j * fabsl(j) / 2.) * celula[0].duto.peri / celula[0].duto.area;
  for (int i = ncel; i > 0; i--) {
    taux = arq.celp[i].textern;
    double rhol = celula[i].fluicol.MasEspFlu(pchute, taux);
    double rhog = 0.;
    double alfa = 1. - hol;
    double rhomix = (1. - alfa) * rhol + alfa * rhog;
    double dxmed = 0.5 * (celula[i].dx + celula[i - 1].dx);
    pchute += ((rhomix * 9.81 * sinl(celula[i].duto.teta) * dxmed + perdafric * dxmed) / 98066.5);
    if (celula[i - 1].acsr.tipo == 7) pchute -= celula[i - 1].acsr.delp;
    if (celula[i - 1].acsr.tipo == 3 && (celula[i - 1].acsr.ipr.Pres - pchute) < (*vg1dSP).localtiny) pchute = 0.99
        * celula[i - 1].acsr.ipr.Pres;
    celula[i - 1].pres = pchute;
  }
  return pchute;
}

double SProd::hidroTramoSecundario(double titulo) {
  double pchute;
  if(arq.ConContEntrada==1)pchute= arq.CCPres.pres[0];
  else pchute=celula[0].pres;
  double taux;
  double hol;
  double bet;
  if(arq.ConContEntrada==1)bet=arq.CCPres.bet[0];
  else bet=celula[0].bet;
  celula[0].bet = bet;
  taux = arq.celp[0].textern;
  double titRef= celula[0].flui.FracMassHidra(pchute, taux);
  if(arq.ConContEntrada==1)celula[0].pres = arq.CCPres.pres[0];
  celula[0].temp = taux;
  double rhol = celula[0].flui.MasEspLiq(celula[0].pres, taux);
  double rhoc = celula[0].fluicol.MasEspFlu(celula[0].pres, taux);
  double rhog = celula[0].flui.MasEspGas(celula[0].pres, taux);
  double titEntra;
  if(arq.ConContEntrada==1)titEntra=arq.CCPres.tit[0];
  else titEntra=titulo;
  celula[0].alf=titEntra*(rhol*(1.-bet)+rhoc*bet)/(rhog*(1.-titEntra)+titEntra*(rhol*(1.-bet)+rhoc*bet));
  for (int i = 0; i < ncel; i++) {
	taux = arq.celp[i].textern;
    rhol = celula[i].flui.MasEspLiq(pchute, taux);
    rhoc = celula[i].fluicol.MasEspFlu(pchute, taux);
    rhog = celula[i].flui.MasEspGas(pchute, taux);
    double tit0= celula[i].flui.FracMassHidra(pchute, taux);
    double delTit=tit0-titRef;
    double novoTit=titulo+delTit*(titulo/titRef);
    double alfa = novoTit*(rhol*(1.-bet)+rhoc*bet)/(rhog*(1.-novoTit)+novoTit*(rhol*(1.-bet)+rhoc*bet));
    celula[i+1].alf=alfa;
    celula[i+1].bet=bet;

    double rhomix = (1. - alfa) * ((1.-bet)*rhol+bet*rhoc) + alfa * rhog;
    double dxmed = 0.5 * (celula[i].dx + celula[i + 1].dx);
    pchute -= ((rhomix * 9.81 * sinl(celula[i].duto.teta) * dxmed) / 98066.5);
    celula[i + 1].pres = pchute;
    celula[i+1].temp = taux;
  }
  return pchute;
}

double SProd::buscaTramoSecVazPerm(double pPartida, int indPartida) {
	//busca de dois chutes iniciais com valores com sinais opostos
	//para marchaProdPerm1 e assim iniciar o prpocesso de calculo de erro de funcao.
	//chute=chute inicial de pressao de fundo, caso chute seja <0,
	//sera feita uma estimativa interna dos valores;
  revPerm=0;
  monitConvPerm=1000.;
  double pchute = pPartida;//inicializando o valor de pchute com o valor da pressao a jusante
  //do choke, pchute sera o valor de chute de fato no processo de busca
  //se o valor de chute>0, pchute=chute, senao, ele e estimado
  double taux;//valor de temperatura auxiliar para o eventual calculo
  //de pchute
  double j = 0.;
  double rmis = 0.;
  double f1 = 0.;
  double perdafric=0.;
  double betaChute=0.;
  if(celula[0].acsr.tipo==2)betaChute=celula[0].acsr.injl.bet;

  for (int i = indPartida; i > 0; i--) {
	  taux = arq.celp[i].textern;
	  if(taux<arq.tmin)taux=arq.tmin;
	  double rhol = celula[i].flui.MasEspLiq(pchute, taux);
	  double rhog = celula[i].flui.MasEspGas(pchute, taux);
	  //se o sistema nao for um anel principal de GL
	  //para a estimativa de pressao, se utilizara so a hidrostatica de liquido, o que dara um
	  //chute inicial de pressao muito alta
	  double alfa = 0.;
	  if(betaChute<0.5){
		  double tit=celula[i].flui.FracMassHidra(pchute, taux);
		  alfa=tit*rhol/(rhog-tit*rhog+tit*rhol);
	  }
	  if(celula[0].acsr.tipo==1)alfa = 1.;
	  double rhomix = (1. - alfa) * rhol + alfa * rhog;
	  double dxmed = 0.5 * (celula[i].dx + celula[i - 1].dx);
	  //avanco da pressao por meio da hidrostatica e da perda por friccao estimada
	  pchute += (rhomix * 9.81 * sinl(celula[i].duto.teta) * dxmed + perdafric * dxmed) / 98066.5;
	  if(arq.usaTabela==1 && (arq.tabent.pmax - pchute) < (*vg1dSP).localtiny)pchute = 0.9*arq.tabent.pmax;
  }
  if(pchute>1000)pchute=1000.;//pressao maxima de chute



  //lista de parametro do metodo
  double pchute2;//segundo chute de pressao da busca
  double pchuteAux=0.;//auxiliar na busca de dos chutes de pressao
  //necessarios para se dar partida no metodo de calculo de raiz
  double val;//val recebe sempre o valor retornado pelo procedimento de marcha
  //neste caso, Ã© a pressao a montante do choke-a pressao da ultima celula, calculada pela
  //marcha
  val = marchaProdPerm2(pchute);
  buscaIni=1;
  //a marcha pode dar problemas, ou a pressao em algum ponto deu acima da pressao estatica de
  //de alguma IPR no meio do caminho, retorna 1e10,
  //ou antes de atingir a ultima celula, a pressao ficou proximo de zero, ou a pressao
  //retorna -1e10, ou a pressao, para o caso PVTSim, ficou acima da pressao maxima da tabela
  //retorna 1e10
  if (val < -0.9e10) {//pressao muito baixa na marcha, deve ser aumentado o valor de chute
		//faz-se uma nova estimativa, sÃ³ que agora admitindo uma hidrostÃ¡tica de Ã¡gua,
		//o que darÃ¡ uma pressao de fundpo mais alta
    pchuteAux = pGSup;
    for (int i = ncel; i > 0; i--) {
      taux = arq.celp[i].textern;
      double rhol = 1000 + 0 * celula[i].flui.MasEspLiq(pchuteAux, taux);
      double rhog = celula[i].flui.MasEspGas(pchuteAux, taux);
      double alfa = 0.;
      if(celula[0].acsr.tipo==1)alfa = 1.;
      else if((*vg1dSP).chaverede==1 && chuteHol<0.5 && chuteHol>-1e-15)alfa=1.-chuteHol*2.;
      double rhomix = (1. - alfa) * rhol + alfa * rhog;
      double dxmed = 0.5 * (celula[i].dx + celula[i - 1].dx);
      pchuteAux += (rhomix * 9.81 * sinl(celula[i].duto.teta) * dxmed + perdafric * dxmed) / 98066.5;
      if(arq.usaTabela==1 && (arq.tabent.pmax - pchuteAux) < (*vg1dSP).localtiny)pchuteAux = 0.9*arq.tabent.pmax;
    }
    if(pchuteAux>1100)pchuteAux=1100;//limite de pchuteAux
  } else if (val > 0.9e10) {//pressao em algum ponto ficou acima de alguma pressao estatica
	  //deve-se diminuir o valor do chute
    pchuteAux = pGSup;
    for (int i = ncel; i > 0; i--) {
      taux = arq.celp[i].textern;
      double rhol = celula[i].flui.MasEspLiq(pchuteAux, taux);
      double rhog = celula[i].flui.MasEspGas(pchuteAux, taux);
      //neste caso, utiliza-se uma fraÃ§Ã£o de vazio alta para a hidrostÃ¡tica
      double alfa = 0.8;
      if(celula[0].acsr.tipo==1)alfa = 1.;
      else if((*vg1dSP).chaverede==1 && chuteHol<0.2 && chuteHol>-1e-15)alfa=1.-chuteHol;
      double rhomix = (1. - alfa) * rhol + alfa * rhog;
      double dxmed = 0.5 * (celula[i].dx + celula[i - 1].dx);
      pchuteAux += (rhomix * 9.81 * sinl(celula[i].duto.teta) * dxmed + perdafric * dxmed) / 98066.5;
      if(arq.usaTabela==1 && (arq.tabent.pmax - pchuteAux) < (*vg1dSP).localtiny)pchuteAux = 0.9*arq.tabent.pmax;
    }
    if(pchuteAux>1100)pchuteAux=1100;
  }

  double mult1=0.9;
  double mult2 =1.1;

  //para o caso de ter dado eerado a primeira marcha, com pchuteAux faz-se uma nova tentativa
  int kontaiter=0;//contador para o laco em que se tentara uma nova estimativa
  //em que ao menos os valores 1e10 ou 1e-10 nÃ£o seja retornados
  double pchuteAux0=pchuteAux;
  if(val < -0.9e10  || val > 0.9e10){
	  double valtemp;
	  valtemp = marchaProdPerm2(pchuteAux);//marcha com pchuteAux
	  if(fabsl(valtemp)>1.01e10){
     		cout<<"#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################"<<endl;
      		if ((*vg1dSP).iterRede > 0) return -1.1e10;
      		else return 1.1e10;
	  }
	  while(valtemp>0.9e10 && val>0.9e10 && kontaiter<50){//estimativa de pressao de fundo ainda alta
		  pchuteAux*=0.99;//reduzindo a estimativa
		  valtemp = marchaProdPerm2(pchuteAux);
		  if(fabsl(valtemp)>1.01e10){
	     		cout<<"#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################"<<endl;
	      		if ((*vg1dSP).iterRede > 0) return -1.1e10;
	      		else return 1.1e10;
		  }
		  kontaiter++;//50 iteracoes no maximo
	  }
	  while(valtemp<-0.9e10 && val<-0.9e10 && kontaiter<=50){//estimativa de pressao de fundo ainda baixa
		  if(celula[0].acsr.tipo==1 || celula[0].acsr.tipo==2 || celula[0].acsr.tipo==10)pchuteAux*=1.1;
		  else pchuteAux*=1.01;//aumentando a estimativa
		  //verificando se este aumento de estimativa foca acima do valor maximo de pressao
		  //de uma eventual tabela PVTSim
		  if(arq.usaTabela==1 && (arq.tabent.pmax - pchuteAux) < (*vg1dSP).localtiny)pchuteAux = 0.9*arq.tabent.pmax;
		  valtemp = marchaProdPerm2(pchuteAux);//nova tentativa
		  if(fabsl(valtemp)>1.01e10){
	     		cout<<"#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################"<<endl;
	      		if ((*vg1dSP).iterRede > 0) return -1.1e10;
	      		else return 1.1e10;
		  }
		  if(kontaiter==50){
			  pchuteAux=0.5*pchuteAux0;
		  }
		  kontaiter++;
	  }
	  valtemp = marchaProdPerm2(pchuteAux);
	  if(fabsl(valtemp)>1.01e10){
     		cout<<"#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################"<<endl;
      		if ((*vg1dSP).iterRede > 0) return -1.1e10;
      		else return 1.1e10;
	  }
	  if(valtemp > -0.9e10  && valtemp < 0.9e10){//conseguiu fazer a marcha atÃƒÂ© o final
		  val=valtemp;
		  pchute=pchuteAux;
	  }
  }
	if(kontaiter>50){//chegou ao limite da iteracao
		//se for em uma iteracao de rede, apos a primeira iteracao
    	if((*vg1dSP).iterRede>0)return -1.1e10;
    	//se logo apÃ³s tem uma simulacao transiente ou se esta na primeira iteracao de rede
     	else return 1.1e10;
	}
	   //caso o laÃ§o anterior tenha levado a estimativa de um valor 1e10 para um valor -1e10
	   //ou tenha levado para um valor de -1e10 para 1e10
	   //ou seja, de um chute de pressao alto demais para finalizar a marcha
	   //para um chute de pressao baixo demais para terminar a marcha ou vice versa
  while ((val < -0.9e10  || val > 0.9e10) && kontaiter<=50) {
    pchute = 0.5 * (pchute + pchuteAux);//busca-se um valor medio
    //entre o alto demais e o baixo demais
    if((fabsl(pchute-pchuteAux)/pchute)<0.001 && val < -0.9e10 ){
  	  pchute=1.05*pchute;
  	  if(arq.usaTabela==1 && (arq.tabent.pmax - pchute) < (*vg1dSP).localtiny)pchute = 0.9*arq.tabent.pmax;
  	  pchuteAux=pchute;
    }

    val = marchaProdPerm2(pchute);
	  if(fabsl(val)>1.01e10){
   		cout<<"#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################"<<endl;
    		if ((*vg1dSP).iterRede > 0) return -1.1e10;
    		else return 1.1e10;
	  }
    kontaiter++;
  }
  if(kontaiter>50){
    		cout<<"#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################"<<endl;
    		if ((*vg1dSP).iterRede > 0) return -1.1e10;
    		else return 1.1e10;
  }

//caso tenha sido possivel obter um chute de pressao em que foi possivel finalizar a marcha
  kontaiter = 0;
  pchute2 = pchute;
  double chutelim = 0.;
  double chuteNeg;
  double chutePos;
  double atenua=1.;
  /*if(celula[0].acsr.tipo==3 && celula[0].acsr.ipr.tipoIPR!=2){
	  if(celula[0].acsr.ipr.ip>2000.)atenua=celula[0].acsr.ipr.ip/2000;
  }
  double reduz=0.9*atenua;
  if(reduz>0.999)reduz=0.999;
  double amplifica=1.1/atenua;
  if(amplifica<1.001)amplifica=1.001;*/
  double reduz=1.-arq.buscaFC;
  double amplifica=1.+arq.buscaFC;
  double aumenta=amplifica;
  if(fabsl(val)<1e-3)return pchute;
  else {
	  if (val < 0.) {//caso em que o chute de pressao foi alto
	  //Vazao no choke>Vazao da mistura na tubulaÃ§Ã£o
	  //calculada pela marcha, isto implica em pressao de chute alta , deve-se agora buscar
	  //uma pressao de chute baixa para que val seja positivo e assim iniciar o processo
	  //de calculo de zero de funcao
		  chuteNeg=pchute;//armazenando o valor de chute de pressao que da o valor negativo
	//a cada nova busca em que val se aproxima de zero, mas ainda negativo
	//chuteNeg Ã© atualizado com a Ãºltima pressao de chute
		  while (val < 0) {
			  if(fabsl(pchute2-pchute)/pchute<(1.-reduz)/10. && kontaiter>50){
				  pchute2*=0.5;
			  }
			  pchuteAux = pchute2;
      //double coef;
      //if((*vg1dSP).chaverede==0)coef=atenuador*0.9;
      //else coef=atenuador*0.99;
      //if(coef>=(1.-localtiny))coef=0.9999;
      //pchute*=coef;
			  if ((*vg1dSP).chaverede == 0) pchute2 *= reduz;//Diminuindo a pressao na busca de val>0
			  else pchute2 *= mult1;//Diminuindo a pressao na busca de val>0
			  if (pchute2 <= chutelim) pchute2 = 0.5 * (pchuteAux + chutelim);//chutelim inicialmente
		//e zero, mas pode acontecer de baixar demais pchute2 ao ponto de val=-1e10
		//(pressao abaixo de 0.5 no meio da marcha), neste caso, chutelim se torna este valor de
		//pchute2, pois, com isto, ja se sabe que nao se pode ir abaixo de chutelim
			  if(arq.usaTabela==1 && (arq.tabent.pmax - pchute2) < (*vg1dSP).localtiny)pchute2 = 0.9*arq.tabent.pmax;
			  val = marchaProdPerm2(pchute2);
			  if(fabsl(val)>1.01e10){
		     		cout<<"#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################"<<endl;
		      		if ((*vg1dSP).iterRede > 0) return -1.1e10;
		      		else return 1.1e10;
			  }
			  if(val<0 && val>-0.9e10)chuteNeg=pchute2;//atualizando o chuteNeg
			  kontaiter++;
			  if (kontaiter > 50) {//limite de iteracoes, falha na busca do segundo chute
			//fim da simulacao ou aviso de falha
				  cout<<"#################PERMANENTE FALHOU EM SUA CONVERGENCIA##############################"<<endl;
				  if ((*vg1dSP).iterRede > 0) return -1.1e10;
				  else return 1.1e10;
			  }
			  while (val < -0.9e10) {//a reduÃ§Ã£o de pressao foi demais e a marcha nÃ£o foi capaz
			//de ir ate o final sem que a pressao ficasse inferior a 0.5kgf/cm2
			//deve-se aumentar a estimativa de pressao baixa
				  chutelim = pchute2;
				  pchute2 = 0.5 * (pchute2 + pchuteAux);//valor intermediario entre a menor pressao
			// que leva a val<0 e a pressao baixa demais
				  if(arq.usaTabela==1 && (arq.tabent.pmax - pchute2) < (*vg1dSP).localtiny)pchute2 = 0.9*arq.tabent.pmax;
				  if(celula[0].acsr.tipo == 3 &&
						  (celula[0].acsr.ipr.Pres - pchute2) <  0.001* celula[0].acsr.ipr.Pres){
        	//pchute2 = 0.99 * celula[0].acsr.ipr.Pres;
					  pchute2=-(10/celula[0].acsr.ipr.ip)+celula[0].acsr.ipr.Pres;
					  if(pchute2<0.999* celula[0].acsr.ipr.Pres)pchute2 = 0.999* celula[0].acsr.ipr.Pres;
				  }
        //if(fabsl(pchute2-pchuteAux)<localtiny)pchute2=0.9*pchuteAux;
				  val = marchaProdPerm2(pchute2);
				  if(fabsl(val)>1.01e10){
			     		cout<<"#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################"<<endl;
			      		if ((*vg1dSP).iterRede > 0) return -1.1e10;
			      		else return 1.1e10;
				  }
				  if(val<0 && val>-0.9e10)chuteNeg=pchute2;
				  kontaiter++;
				  if (kontaiter > 50) {
					  cout<<"#################PERMANENTE FALHOU EM SUA CONVERGENCIA##############################"<<endl;
					  if ((*vg1dSP).iterRede > 0) return -1.1e10;
					  else return 1.1e10;
				  }
			  }
		  }
		  chutePos=pchute2;
	  } else if (val > 0.) {//caso em que Vazao no choke<Vazao da mistura na tubulaÃ§Ã£o,
	  //isto implica em pressao de chute baixa , deve-se agora buscar
	  //uma pressao de chute alta para que val seja negativo e assim iniciar o processo
	  //de calculo de zero de funcao
		  chutePos=pchute;//armazenando o valor de chute de pressao que da o valor positivo
		//a cada nova busca em que val se aproxima de zero, mas ainda positivo
		//chutePos e atualizado com a Ãºltima pressao de chute
		  while (val > 0) {
			  pchuteAux = pchute2;
			  if ((*vg1dSP).chaverede == 0) pchute2 *= amplifica;//Aumentando a pressao na busca de val>0
			  else pchute2 *= mult2;//Aumentando a pressao na busca de val>0
      //if (pchute2 >= chutelim) pchute2 = 0.5 * (pchuteAux + chutelim);
			  if(arq.usaTabela==1 && (arq.tabent.pmax - pchute2) < (*vg1dSP).localtiny)pchute2 = 0.9*arq.tabent.pmax;
			  int limpres=0;
			  val = marchaProdPerm2(pchute2);
			  if(fabsl(val)>1.01e10){
		     		cout<<"#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################"<<endl;
		      		if ((*vg1dSP).iterRede > 0) return -1.1e10;
		      		else return 1.1e10;
			  }
			  if(val>0. && limpres==1){
				  int iterpres=0;
				  while(val>0 && iterpres<10){
					  pchute2*=1.001;
					  val = marchaProdPerm2(pchute2);
					  if(fabsl(val)>1.01e10){
				     		cout<<"#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################"<<endl;
				      		if ((*vg1dSP).iterRede > 0) return -1.1e10;
				      		else return 1.1e10;
					  }
					  iterpres++;
				  }
				  if(iterpres>=10){
					  cout<<"#################PERMANENTE FALHOU EM SUA CONVERGENCIA##############################"<<endl;
					  if ((*vg1dSP).iterRede > 0) return -1.1e10;
					  else return 1.1e10;
				  }
			  }
			  if(val>0 && val<0.9e10)chutePos=pchute2;//atualizando o chutePos
			  kontaiter++;
			  if (kontaiter > 50) {//limite de iteracoes, falha na busca do segundo chute
			//fim da simulacao ou aviso de falha
				  cout<<"#################PERMANENTE FALHOU EM SUA CONVERGENCIA##############################"<<endl;
				  if ((*vg1dSP).iterRede > 0) return -1.1e10;
				  else return 1.1e10;
			  }
			  while (val > 0.9e10) {//o incremento de pressao foi demais e a marcha nao foi capaz
			//de ir ate o final sem que a pressao ficasse maior do que a pressao estatica
			//em um eventual IPR no meio da marcha ou maior que o limitre maximo de pressao
			//da tabela PVTSim, quando for este o caso
			//deve-se diminuir a estimativa de pressao baixa
				  chutelim = pchute2;
				  pchute2 = 0.5 * (pchute2 + pchuteAux);//valor intermediario entre a maior pressao
			// que leva a val>0 e a pressao alta demais
				  if(arq.usaTabela==1 && (arq.tabent.pmax - pchute2) < (*vg1dSP).localtiny)pchute2 = 0.9*arq.tabent.pmax;
        //if(fabsl(pchute2-pchuteAux)<localtiny)pchute2=1.1*pchuteAux;
				  val = marchaProdPerm2(pchute2);
				  if(fabsl(val)>1.01e10){
			     		cout<<"#################PERMANENTE FALHOU EM SUA CONVERGÃŠNCIA##############################"<<endl;
			      		if ((*vg1dSP).iterRede > 0) return -1.1e10;
			      		else return 1.1e10;
				  }
				  if(val>0 && val<0.9e10)chutePos=pchute2;
				  kontaiter++;

				  if (kontaiter > 50) {
					  cout<<"#################PERMANENTE FALHOU EM SUA CONVERGENCIA##############################"<<endl;
					  if ((*vg1dSP).iterRede > 0) return -1.1e10;
					  else return 1.1e10;
				  }

			  }
		  }
		  chuteNeg=pchute2;
	  }
  //return falsacorda(pchute, pchute2,1,1);
	  return zriddr(chuteNeg, chutePos, 1, 1);//com as duas estimativas de pressao
  //em posicoes de sinal contrario da curva, inicia-se o processo de calculo de zero
  //de funcao
  //return zbrent(pchute, pchute2,1,1); //no caso mono deu problema com este solver, funcionou melhor com a falsa corda
  }
}

